// ── ImportState ───────────────────────────────────────────────────────────────

func (r *QConnectAIGuardrailResource) ImportState(ctx context.Context, req resource.ImportStateRequest, resp *resource.ImportStateResponse) {
	parts := strings.Split(req.ID, "/")
	if len(parts) != 2 || parts[0] == "" || parts[1] == "" {
		resp.Diagnostics.AddError("Invalid import ID", "Expected <assistant_id>/<ai_guardrail_id>")
		return
	}
	resp.Diagnostics.Append(resp.State.SetAttribute(ctx, path.Root("assistant_id"), parts[0])...)
	resp.Diagnostics.Append(resp.State.SetAttribute(ctx, path.Root("ai_guardrail_id"), parts[1])...)
}

// ── flattenAllPolicies (shared by Create, Read, Update) ───────────────────────

func flattenAllPolicies(ctx context.Context, g *qconnecttypes.AIGuardrailData, data *QConnectAIGuardrailResourceModel) diag.Diagnostics {
	var diags diag.Diagnostics

	contentObj, d := flattenContentPolicyConfig(ctx, g.ContentPolicyConfig)
	diags.Append(d...)
	data.ContentPolicyConfig = contentObj

	topicObj, d := flattenTopicPolicyConfig(ctx, g.TopicPolicyConfig)
	diags.Append(d...)
	data.TopicPolicyConfig = topicObj

	wordObj, d := flattenWordPolicyConfig(ctx, g.WordPolicyConfig)
	diags.Append(d...)
	data.WordPolicyConfig = wordObj

	sensitiveObj, d := flattenSensitiveInformationPolicyConfig(ctx, g.SensitiveInformationPolicyConfig)
	diags.Append(d...)
	data.SensitiveInformationPolicyConfig = sensitiveObj

	groundingObj, d := flattenContextualGroundingPolicyConfig(ctx, g.ContextualGroundingPolicyConfig)
	diags.Append(d...)
	data.ContextualGroundingPolicyConfig = groundingObj

	return diags
}

