func expandContentPolicyConfig(ctx context.Context, obj types.Object) (*qconnecttypes.AIGuardrailContentPolicyConfig, diag.Diagnostics) {
	var diags diag.Diagnostics
	if obj.IsNull() || obj.IsUnknown() {
		return nil, diags
	}

	var m contentPolicyConfigModel
	diags.Append(obj.As(ctx, &m, objectAsOptions())...)
	if diags.HasError() {
		return nil, diags
	}

	var items []contentFilterConfigModel
	diags.Append(m.FiltersConfig.ElementsAs(ctx, &items, false)...)
	if diags.HasError() {
		return nil, diags
	}

	filters := make([]qconnecttypes.GuardrailContentFilterConfig, 0, len(items))
	for _, item := range items {
		filters = append(filters, qconnecttypes.GuardrailContentFilterConfig{
			InputStrength:  qconnecttypes.GuardrailFilterStrength(item.InputStrength.ValueString()),
			OutputStrength: qconnecttypes.GuardrailFilterStrength(item.OutputStrength.ValueString()),
			Type:           qconnecttypes.GuardrailContentFilterType(item.Type.ValueString()),
		})
	}

	return &qconnecttypes.AIGuardrailContentPolicyConfig{FiltersConfig: filters}, diags
}

